mapper.sql:
WHERE 1 = 1

    AND l.admin_id = #{adminId}


    AND l.action = #{action}


    AND l.target = #{target}


    AND (
        l.action LIKE CONCAT('%', #{keyword}, '%')
        OR l.target LIKE CONCAT('%', #{keyword}, '%')
        OR l.detail LIKE CONCAT('%', #{keyword}, '%')
        OR l.ip LIKE CONCAT('%', #{keyword}, '%')
        OR COALESCE(au.account, '') LIKE CONCAT('%', #{keyword}, '%')
        OR COALESCE(au.name, '') LIKE CONCAT('%', #{keyword}, '%')
    )

WHERE 1 = 1

    AND t.region = #{region}


    AND t.biz_type = #{bizType}




            AND 1 = 0


            AND t.biz_type IN

                #{allowedBizType}





    AND t.status = #{status}

mapper.select:
SELECT detail
FROM audit_log
WHERE action = #{action}
  AND target = #{target}
ORDER BY id DESC
LIMIT 1
